export const routes = [
  {
    path: 'checkout',
    loadChildren: () => loadRemoteModule('checkout', './Routes'),
  },
];

export default [
  { path: 'login', loadComponent: () => import('./login.page') },
  { path: 'callback', loadComponent: () => import('./callback.page') },
];

@Component({ templateUrl: './product-list.page.html' })
export class ProductListPage {
  products = inject(CatalogApi).list();
}

export const remoteRoutes = [
  {
    path: '',
    loadComponent: () => import('./checkout.page'),
  },
];

@Component({ templateUrl: './checkout.page.html' })
export class CheckoutPage {
  submit() { return inject(CheckoutApi).confirm(); }
}

export type ShellNavigation = {
  goToCart(): void;
  goToLogin(returnUrl: string): void;
};
